import{_ as e,c as a,o as n,ae as i}from"./chunks/framework.CeIuOzFV.js";const u=JSON.parse('{"title":"Widgets","description":"","frontmatter":{},"headers":[],"relativePath":"user-manual/content-management/widgets.md","filePath":"user-manual/content-management/widgets.md"}'),l={name:"user-manual/content-management/widgets.md"};function d(o,t,r,s,g,c){return n(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="widgets" tabindex="-1">Widgets <a class="header-anchor" href="#widgets" aria-label="Permalink to &quot;Widgets&quot;">​</a></h1><h2 id="available-widgets" tabindex="-1">Available Widgets <a class="header-anchor" href="#available-widgets" aria-label="Permalink to &quot;Available Widgets&quot;">​</a></h2><p>The following widgets can currently be used to compose pages of:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Widget</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">Avatar</td><td style="text-align:left;">A central image, rounded, with an optional subtext.</td></tr><tr><td style="text-align:left;">Buttons</td><td style="text-align:left;">A list of buttons that open new pages. Each button can be styled individually.</td></tr><tr><td style="text-align:left;">Image Gallery</td><td style="text-align:left;">A widget containing one or more images and optional text. The position of the image(s) and text can be configured.</td></tr><tr><td style="text-align:left;">Info Box</td><td style="text-align:left;">An info box containing a heading and text content. Can be colored in green, red and yellow.</td></tr><tr><td style="text-align:left;">Item Search</td><td style="text-align:left;">A widget providing input for an item search. If a search term is configured, the search result will directly be displayed.</td></tr><tr><td style="text-align:left;">Page Title</td><td style="text-align:left;">A page title spanning an optional image across the browser windows and a bold, central title text.</td></tr><tr><td style="text-align:left;">Text</td><td style="text-align:left;">A heading with text content. Markdown is supported to further structure and format the text content.</td></tr></tbody></table><h2 id="audio-content" tabindex="-1">Audio Content <a class="header-anchor" href="#audio-content" aria-label="Permalink to &quot;Audio Content&quot;">​</a></h2><p>Widgets with text content can have audio files generated from their text using AI-powered text-to-speech (TTS). The generated audio can be used e.g. in content exports to provide an audio experience of the collection.</p><p>To use this feature, AI must be enabled and configured in the <a href="./../settings/ai.html">AI Configuration</a>.</p>',7)])])}const f=e(l,[["render",d]]);export{u as __pageData,f as default};
